  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Aufschlüsselung des Transfers vom 13. Juli &amp; Gesamtbestände der Regierung</text>
  <g font-family="sans-serif">
    <rect x="30" y="55" width="300" height="130" rx="10" fill="#2a1414" stroke="#f87171" stroke-width="1.3"/>
    <text x="180" y="80" fill="#fca5a5" font-size="14" font-weight="700" text-anchor="middle">3.940 BTC (~$243.95M)</text>
    <text x="50" y="105" fill="#e4e4e7" font-size="12">→ Teil der Strategic Bitcoin Reserve</text>
    <text x="50" y="127" fill="#a1a1aa" font-size="12">· Verkaufsverbot (Executive Order März 2025)</text>
